381	                    .filter(|&t| t > 0)
382	                    .unwrap_or(n);
383	                Some(Arc::new(TokenBucket::new(
384	                    n as usize,
385	                    rate_limit_tokens as usize,
386	                )))
387	            }
388	        };
389	        self
