482	    /// Create and initialize MCP manager with empty config
483	    ///
484	    /// This initializes the MCP manager with an empty config and default settings.
485	    /// MCP servers will be registered later via the InitializeMcpServers job.
486	    async fn with_mcp_manager(mut self, _router_config: &RouterConfig) -> Result<Self, String> {
487	        // Create OnceLock container
488	        let mcp_manager_lock = Arc::new(OnceLock::new());
489	
490	        // Always create with empty config and defaults
491	        debug!("Initializing MCP manager with empty config and default settings (5 min TTL, 100 max connections)");
492	
493	        let empty_config = smg_mcp::McpConfig {
494	            servers: Vec::new(),
495	            pool: Default::default(),
496	            proxy: None,
497	            warmup: Vec::new(),
498	            inventory: Default::default(),
499	        };
500	
501	        let manager = McpManager::with_defaults(empty_config)
502	            .await
503	            .map_err(|e| format!("Failed to initialize MCP manager with defaults: {}", e))?;
504	
505	        // Store the initialized manager in the OnceLock
506	        mcp_manager_lock
507	            .set(Arc::new(manager))
508	            .map_err(|_| "Failed to set MCP manager in OnceLock".to_string())?;
509	
510	        self.mcp_manager = Some(mcp_manager_lock);
511	        Ok(self)
512	    }
513	
514	    /// Create wasm manager if enabled in config
515	    fn with_wasm_manager(mut self, config: &RouterConfig) -> Result<Self, String> {
516	        self.wasm_manager = if config.enable_wasm {
517	            Some(Arc::new(
518	                WasmModuleManager::new(WasmRuntimeConfig::default())
519	                    .map_err(|e| format!("Failed to initialize WASM module manager: {}", e))?,
520	            ))
521	        } else {
522	            None
523	        };
524	        Ok(self)
525	    }
